public class UnsafeNativeMethods
{
    [DllImport("kernel32.dll")]
    public static extern bool CloseHandle(IntPtr hObject); // Noncompliant - public native method
}

compliant:
public class SafeNativeMethods
{
    [DllImport("kernel32.dll")]
    private static extern bool CloseHandle(IntPtr hObject); // Compliant - private

    public static bool CloseSafely(IntPtr handle)
    {
        return handle != IntPtr.Zero && CloseHandle(handle); // Wrapped with validation
    }
}
